# Category: path_traversal

import os
from flask import Flask, request, jsonify, send_from_directory, abort

app = Flask(__name__)

# Configuration
# This is the base directory where user files are stored.
# In a real application, this would be per-user and configured securely.
UPLOAD_FOLDER = os.path.abspath('user_files')
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

def get_full_path(relative_path):
    """
    Constructs and normalizes the full path, ensuring it stays within UPLOAD_FOLDER.
    """
    # Join the base folder with the user-provided relative path
    full_path = os.path.join(app.config['UPLOAD_FOLDER'], relative_path)
    # Normalize the path to handle '..' and clean up
    normalized_path = os.path.normpath(full_path)

    # Security check: Ensure the normalized path is still within the UPLOAD_FOLDER
    # This prevents directory traversal attacks where '..' could lead outside
    if not normalized_path.startswith(app.config['UPLOAD_FOLDER']):
        raise ValueError("Attempted to access path outside of the user's root directory.")

    return normalized_path

@app.route('/list', methods=['GET'])
def list_directory():
    """
    Lists the contents of a directory.
    Query parameter: 'path' (relative to user's root)
    """
    relative_path = request.args.get('path', '')

    try:
        target_path = get_full_path(relative_path)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    if not os.path.exists(target_path):
        return jsonify({"error": "Path not found"}), 404
    if not os.path.isdir(target_path):
        return jsonify({"error": "Path is not a directory"}), 400

    contents = []
    try:
        for item in os.listdir(target_path):
            item_full_path = os.path.join(target_path, item)
            is_dir = os.path.isdir(item_full_path)
            contents.append({
                "name": item,
                "type": "directory" if is_dir else "file",
                "size": os.path.getsize(item_full_path) if not is_dir else None,
            })
    except Exception as e:
        return jsonify({"error": f"Failed to list directory: {e}"}), 500

    return jsonify({"path": relative_path, "contents": contents})

@app.route('/download', methods=['GET'])
def download_file():
    """
    Downloads a specific file.
    Query parameter: 'path' (relative to user's root)
    """
    relative_path = request.args.get('path')
    if not relative_path:
        return jsonify({"error": "Path parameter is required"}), 400

    try:
        target_path = get_full_path(relative_path)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    if not os.path.exists(target_path):
        return jsonify({"error": "File not found"}), 404
    if os.path.isdir(target_path):
        return jsonify({"error": "Cannot download a directory"}), 400

    directory = os.path.dirname(target_path)
    filename = os.path.basename(target_path)

    try:
        # send_from_directory handles security checks (e.g., ensuring path is within the base directory)
        # However, our get_full_path already does this, providing an extra layer.
        return send_from_directory(directory, filename, as_attachment=True)
    except Exception as e:
        return jsonify({"error": f"Failed to download file: {e}"}), 500

@app.route('/info', methods=['GET'])
def get_file_info():
    """
    Gets detailed information about a file or directory.
    Query parameter: 'path' (relative to user's root)
    """
    relative_path = request.args.get('path')
    if not relative_path:
        return jsonify({"error": "Path parameter is required"}), 400

    try:
        target_path = get_full_path(relative_path)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    if not os.path.exists(target_path):
        return jsonify({"error": "Path not found"}), 404

    try:
        stat_info = os.stat(target_path)
        is_dir = os.path.isdir(target_path)
        info = {
            "name": os.path.basename(target_path),
            "type": "directory" if is_dir else "file",
            "size": stat_info.st_size if not is_dir else None,
            "created_at": stat_info.st_ctime,
            "modified_at": stat_info.st_mtime,
            "last_access_at": stat_info.st_atime,
            # Add more info as needed, e.g., permissions if relevant
        }
        return jsonify({"path": relative_path, "info": info})
    except Exception as e:
        return jsonify({"error": f"Failed to get info: {e}"}), 500

